19	/**
20	 * Extracts stat leaders and scoring plays from ESPN summary payloads.
21	 * The summary shape varies per sport: football has top-level scoringPlays,
22	 * hockey and baseball have plays (filtered on scoringPlay=true), soccer has
23	 * keyEvents (filtered on scoringPlay=true). Leaders share one nesting across
24	 * sports; baseball summaries have no top-level leaders, so none are stored.
25	 */
26	public class EspnSummaryDetailsMapper {
27	
28	    public List<GameLeader> toLeaders(EspnBoxscoreResponse summary, int gameId) {
29	        List<GameLeader> result = new ArrayList<>();
30	        JsonNode teamBlocks = summary.getLeaders();
31	        if (teamBlocks == null || !teamBlocks.isArray()) {
32	            return result;
33	        }
34	        for (JsonNode teamBlock : teamBlocks) {
35	            Integer teamId = intOrNull(teamBlock.path("team").path("id"));
36	            if (teamId == null) {
37	                continue;
38	            }
39	            for (JsonNode category : teamBlock.path("leaders")) {
40	                String statName = textOrNull(category.path("name"));
41	                JsonNode topLeader = category.path("leaders").path(0);
42	                if (statName == null || topLeader.isMissingNode()) {
43	                    continue;
44	                }
45	                result.add(GameLeader.builder()
46	                        .key(new GameLeaderKey(gameId, teamId, statName))
47	                        .displayName(textOrNull(category.path("displayName")))
48	                        .statValue(doubleOrNull(topLeader.path("value")))
49	                        .displayValue(textOrNull(topLeader.path("displayValue")))
50	                        .playerName(textOrNull(topLeader.path("athlete").path("fullName")))
51	                        .playerShortName(textOrNull(topLeader.path("athlete").path("shortName")))
52	                        .build());
53	            }
54	        }
55	        return result;
56	    }
57	
58	    public List<ScoringPlay> toScoringPlays(EspnBoxscoreResponse summary, League league, Game game) {
59	        List<ScoringPlay> result = new ArrayList<>();
60	        JsonNode source = scoringPlaySource(summary, league);
61	        if (source == null || !source.isArray()) {
62	            return result;
63	        }
64	        int sequence = 0;
65	        Set<String> seenAtBatScores = new HashSet<>();
66	        for (JsonNode play : source) {
67	            // Football payloads list only scoring plays; hockey/soccer/baseball
68	            // list all plays/events and flag the scoring ones.
69	            if (league.getSport() != Sport.FOOTBALL && !play.path("scoringPlay").asBoolean(false)) {
70	                continue;
71	            }
72	            // Baseball flags both the event play (e.g. Stolen Base) and the
73	            // at-bat's Play Result for the same run; keep one per at-bat score
74	            // state so distinct runs within an at-bat still both survive.
75	            String atBatId = textOrNull(play.path("atBatId"));
76	            if (atBatId != null) {
77	                String dedupeKey = atBatId + "|" + intOrNull(play.path("homeScore"))
78	                        + "|" + intOrNull(play.path("awayScore"));
79	                if (!seenAtBatScores.add(dedupeKey)) {
80	                    continue;
81	                }
82	            }
83	            String playId = textOrNull(play.path("id"));
84	            if (playId == null) {
85	                playId = "seq-" + sequence;
86	            }
87	            String teamId = textOrNull(play.path("team").path("id"));
88	            result.add(ScoringPlay.builder()
89	                    .key(new ScoringPlayKey(game.getId(), playId))
90	                    .teamId(teamId)
91	                    .teamAbbreviation(resolveTeamAbbreviation(play, teamId, game))
92	                    .displayText(textOrNull(play.path("text")))
93	                    .homeScore(intOrNull(play.path("homeScore")))
94	                    .awayScore(intOrNull(play.path("awayScore")))
95	                    .scoringType(resolveScoringType(play))
96	                    .period(intOrNull(play.path("period").path("number")))
97	                    .clock(textOrNull(play.path("clock").path("displayValue")))
98	                    .sequence(sequence++)
99	                    .build());
100	        }
101	        return result;
102	    }
103	
104	    private JsonNode scoringPlaySource(EspnBoxscoreResponse summary, League league) {
105	        return switch (league.getSport()) {
106	            case FOOTBALL -> summary.getScoringPlays();
107	            case HOCKEY, BASEBALL -> summary.getPlays();
108	            case SOCCER -> summary.getKeyEvents();
109	        };
110	    }
111	
112	    private String resolveScoringType(JsonNode play) {
113	        String fromScoringType = textOrNull(play.path("scoringType").path("abbreviation"));
114	        if (fromScoringType != null) {
115	            return fromScoringType;
116	        }
117	        String fromTypeAbbreviation = textOrNull(play.path("type").path("abbreviation"));
118	        if (fromTypeAbbreviation != null) {
119	            return fromTypeAbbreviation;
120	        }
121	        return textOrNull(play.path("type").path("text"));
122	    }
123	
124	    private String resolveTeamAbbreviation(JsonNode play, String teamId, Game game) {
125	        String fromPlay = textOrNull(play.path("team").path("abbreviation"));
126	        if (fromPlay != null) {
127	            return fromPlay;
128	        }
129	        if (teamId == null) {
130	            return null;
131	        }
132	        Team home = game.getHomeTeam();
133	        if (home != null && home.getTeamKey() != null
134	                && teamId.equals(String.valueOf(home.getTeamKey().getTeamId()))) {
135	            return home.getAbbreviation();
136	        }
137	        Team away = game.getAwayTeam();
138	        if (away != null && away.getTeamKey() != null
139	                && teamId.equals(String.valueOf(away.getTeamKey().getTeamId()))) {
140	            return away.getAbbreviation();
141	        }
142	        return null;
143	    }
144	
145	    private String textOrNull(JsonNode node) {
146	        if (node.isMissingNode() || node.isNull() || !node.isValueNode()) {
147	            return null;
148	        }
149	        String text = node.asText();
150	        return text.isEmpty() ? null : text;
151	    }
152	
153	    private Integer intOrNull(JsonNode node) {
154	        if (node.isMissingNode() || node.isNull() || !node.isValueNode()) {
155	            return null;
156	        }
157	        if (node.isNumber()) {
158	            return node.asInt();
159	        }
160	        try {
161	            return Integer.parseInt(node.asText().trim());
162	        } catch (NumberFormatException e) {
163	            return null;
164	        }
165	    }
