            if (entry.getKey().getTeamId() == this.getHomeTeam().getTeamKey().getTeamId()) {
                homeStats.put(statName, statValue);
            } else {
                awayStats.put(statName, statValue);
            }
        }
        return new StatResponse(homeStats, awayStats);
